import{Box}from"../primitives/Box.js";class Analyser extends Box{constructor(){super(),this.node=this.c.createAnalyser(),this.boostNode=this.c.createGain(),this.inNode.connect(this.boostNode).connect(this.node).connect(this.wetGainNode),this.node.fftSize=2*Math.max(this.bands,16),this.node.smoothingTimeConstant=this.smoothing,this.dataFrequencies=new Uint8Array(this.bands),this.dataTime=new Float32Array(this.node.frequencyBinCount),this.mixInitial=0,this.mirrorParams({gain:this.boostNode.gain})}getFrequencyData(){return this.node.getByteFrequencyData(this.dataFrequencies),this.dataFrequencies}getTimeData(){return this.node.getFloatTimeDomainData(this.dataTime),this.dataTime}get bands(){let value=this.getAttribute("bands");return value?parseFloat(value):16}set bands(value){this.setAttribute("bands",value)}get smoothing(){let value=this.getAttribute("smoothing");return value?parseFloat(value):0}set smoothing(value){this.setAttribute("smoothing",value)}get gain(){let value=this.getAttribute("gain");return value?parseFloat(value):1}set gain(value){this.setAttribute("gain",value)}}export{Analyser};